const statsRaw = $('Fetch Geo Stats (7 days)').first().json;
const stats = statsRaw?.data?.result?.data || statsRaw?.data || (Array.isArray(statsRaw) ? statsRaw : []);

if (!Array.isArray(stats) || stats.length === 0) {
  return [{ json: { action: 'NONE', reason: 'No geo stats data' } }];
}

// Flatten stats into rows for DB insert
const results = [];
stats.forEach(d => {
  const adId = d.ad_id;
  const country = d.country_code;
  if (!adId || !country) return;

  const spend = Number(d.money) || 0;
  const revenue = Number(d.postbacks_confirmed_money) || 0;
  const roi = spend > 0 ? Math.round((revenue - spend) / spend * 10000) / 100 : 0;

  results.push({
    json: {
      ad_id: adId,
      country_code: country,
      shows: Number(d.shows_count) || 0,
      clicks: Number(d.clicks_count) || 0,
      spend: Math.round(spend * 100) / 100,
      revenue: Math.round(revenue * 100) / 100,
      roi: roi
    }
  });
});

return results;
